#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
using namespace std;
const int N = 25;
const int M = 2e5+5;
const int INF = 0x3f3f3f3f;
int n,m,St,Ed,dis[M];
int tot=1,head[M],to[M],wei[M],cst[M],nxt[M];
bool vis[M];queue<int> q;
int hS,hT,ss[N][N],tt[N][N],Ans,fus;
int dx[]={1,0,-1,0,1,1,-1,-1};
int dy[]={0,1,0,-1,1,-1,1,-1};
int read(){
    int su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
void Add_edge(int x,int y,int z,int w){
    to[++tot]=y,wei[tot]=z,cst[tot]=w;
    nxt[tot]=head[x],head[x]=tot;
    to[++tot]=x,wei[tot]=0,cst[tot]=-w;
    nxt[tot]=head[y],head[y]=tot;return;
}
int Num(int x,int y,int k){return (x-1)*m+y+k*n*m;}
bool SPFA_canit(){
    while(!q.empty())q.pop();
    memset(dis,0x3f,sizeof(dis));
    memset(vis,0,sizeof(vis));
    q.push(St),dis[St]=0,vis[St]=1;
    while(!q.empty()){
        int u=q.front();vis[u]=0;q.pop();
        for(int i=head[u];i;i=nxt[i]){
            if(!wei[i])continue;int v=to[i];
            if(dis[v]>dis[u]+cst[i]){
                dis[v]=dis[u]+cst[i];
                if(!vis[v])vis[v]=1,q.push(v);
            }
        }
    }return dis[Ed]!=INF;
}
int DFS_flow(int u,int flw){
    if(!flw||u==Ed)return flw;
    int flow=0;vis[u]=1;
    for(int i=head[u];i;i=nxt[i]){
        int v=to[i];
        if(vis[v]||dis[u]+cst[i]!=dis[v])continue;
        int tmp=DFS_flow(v,min(flw,wei[i]));
        if(tmp<=0)continue;
        wei[i]-=tmp,wei[i^1]+=tmp;
        flow+=tmp,flw-=tmp;
        if(!flw){vis[u]=0;break;}
    }return flow;
}
int main(){
    n=read(),m=read();
    St=2*n*m+1,Ed=St+1;
    for(int i=1;i<=n;i++)
        for(int j=1;j<=m;j++){
            char h;cin>>h;
            if(h=='1')ss[i][j]++,hS++;
        }
    for(int i=1;i<=n;i++)
        for(int j=1;j<=m;j++){
            char h;cin>>h;
            if(h=='1')tt[i][j]++,hT++;
        }
    if(hS!=hT){cout<<"-1\n";return 0;}
    for(int i=1;i<=n;i++)
        for(int j=1;j<=m;j++){
            if(ss[i][j]&&!tt[i][j])
                Add_edge(St,Num(i,j,0),1,0),fus++;
            if(!ss[i][j]&&tt[i][j])
                Add_edge(Num(i,j,1),Ed,1,0);
        }
    for(int i=1;i<=n;i++)
        for(int j=1;j<=m;j++){
            char h;cin>>h;int x=h-'0';
            Add_edge(Num(i,j,0),Num(i,j,1),x/2,0);
            if(ss[i][j]!=tt[i][j]&&x%2==1)
                Add_edge(Num(i,j,0),Num(i,j,1),1,0);
            for(int k=0;k<8;k++){
                int x2=i+dx[k],y2=j+dy[k];
                if(x2<1||x2>n||y2<1||y2>m)continue;
                Add_edge(Num(i,j,1),Num(x2,y2,0),INF,1);
            }
        }
    while(SPFA_canit()){
        int dp=DFS_flow(St,INF);
        fus-=dp,Ans+=dp*dis[Ed];
    }if(fus)cout<<"-1\n";else cout<<Ans<<"\n";
    return 0;
}
